import{_ as a,c as r,o as e,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Часто задаваемые вопросы: устранение неполадок и решения | Antigravity-Manager","description":"Ознакомьтесь с методами устранения наиболее частых проблем Antigravity Tools. Включает учетные записи, ошибки аутентификации, ограничения и другие типичные сценарии.","frontmatter":{"layout":"page","title":"Часто задаваемые вопросы: устранение неполадок и решения | Antigravity-Manager","sidebarTitle":"Что делать при возникновении ошибки","subtitle":"Часто задаваемые вопросы: устранение неполадок и решения","description":"Ознакомьтесь с методами устранения наиболее частых проблем Antigravity Tools. Включает учетные записи, ошибки аутентификации, ограничения и другие типичные сценарии.","order":4},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/faq/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/faq/index.md"}'),n={name:"ru/lbjlaq/Antigravity-Manager/faq/index.md"};function o(d,t,l,s,h,g){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="часто-задаваемые-вопросы" tabindex="-1">Часто задаваемые вопросы <a class="header-anchor" href="#часто-задаваемые-вопросы" aria-label="Permalink to &quot;Часто задаваемые вопросы&quot;">​</a></h1><p>В этой главе собраны наиболее часто встречающиеся коды ошибок и аномальные сценарии при использовании Antigravity Tools, помогая вам быстро определить коренную причину проблемы и найти решение.</p><h2 id="содержание-главы" tabindex="-1">Содержание главы <a class="header-anchor" href="#содержание-главы" aria-label="Permalink to &quot;Содержание главы&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Тип проблемы</th><th>Страница</th><th>Описание</th></tr></thead><tbody><tr><td>Учетная запись недействительна</td><td><a href="./invalid-grant/">invalid_grant и автоматическое отключение учетной записи</a></td><td>Внезапно учетная запись стала недоступной? Узнайте причину недействительности OAuth-токена и процесс восстановления</td></tr><tr><td>Ошибка аутентификации</td><td><a href="./auth-401/">401/Ошибка аутентификации</a></td><td>Запрос отклонен? Проверьте конфигурацию auth_mode и формат заголовков</td></tr><tr><td>Ошибка ограничения</td><td><a href="./429-rotation/">429/Ошибка емкости</a></td><td>Частые 429? Разберите недостаток квоты на уровне распределения и ограничение скорости нисходящего потока, используйте стратегию ротации для уменьшения влияния</td></tr><tr><td>Ошибка пути</td><td><a href="./404-base-url/">404/Несовместимость пути</a></td><td>Ошибка интерфейса 404? Решите проблему объединения Base URL и префикса /v1</td></tr><tr><td>Прерывание потока</td><td><a href="./streaming-0token/">Прерывание потока/0 Token/Недействительность подписи</a></td><td>Прерванный или пустой ответ? Узнайте о механизме самовосстановления прокси и пути устранения неполадок</td></tr></tbody></table><h2 id="рекомендуемыи-путь-обучения" tabindex="-1">Рекомендуемый путь обучения <a class="header-anchor" href="#рекомендуемыи-путь-обучения" aria-label="Permalink to &quot;Рекомендуемый путь обучения&quot;">​</a></h2><p><strong>Устранение неполадок по коду ошибки</strong>: при возникновении конкретной ошибки переходите непосредственно на соответствующую страницу.</p><p><strong>Систематическое изучение</strong>: если вы хотите всесторонне узнать о возможных проблемах, рекомендуется читать в следующем порядке:</p><ol><li><strong><a href="./404-base-url/">404/Несовместимость пути</a></strong> — самая частая проблема при подключении, обычно первая ловушка</li><li><strong><a href="./auth-401/">401/Ошибка аутентификации</a></strong> — путь верен, но запрос отклонен, проверьте конфигурацию аутентификации</li><li><strong><a href="./invalid-grant/">invalid_grant и автоматическое отключение учетной записи</a></strong> — проблемы на уровне учетных записей</li><li><strong><a href="./429-rotation/">429/Ошибка емкости</a></strong> — запрос успешен, но ограничен</li><li><strong><a href="./streaming-0token/">Прерывание потока/0 Token/Недействительность подписи</a></strong> — расширенные вопросы, касающиеся потоковых ответов и механизмов подписи</li></ol><h2 id="предварительные-условия" tabindex="-1">Предварительные условия <a class="header-anchor" href="#предварительные-условия" aria-label="Permalink to &quot;Предварительные условия&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Рекомендуется сначала выполнить</p><ul><li><a href="./../start/proxy-and-first-client/">Запуск локального обратного прокси и подключение первого клиента</a> — убедитесь, что базовая среда работает</li><li><a href="./../start/add-account/">Добавление учетной записи</a> — изучите правильный способ добавления учетных записей</li></ul></div><h2 id="следующие-шаги" tabindex="-1">Следующие шаги <a class="header-anchor" href="#следующие-шаги" aria-label="Permalink to &quot;Следующие шаги&quot;">​</a></h2><p>После устранения неполадок вы можете продолжить углубленное изучение:</p><ul><li><strong><a href="./../advanced/scheduling/">Высокодоступное планирование</a></strong> — используйте стратегии ротации и повторов для уменьшения частоты возникновения ошибок</li><li><strong><a href="./../advanced/monitoring/">Proxy Monitor</a></strong> — используйте систему журналов для отслеживания деталей запросов</li><li><strong><a href="./../advanced/config/">Полная конфигурация</a></strong> — узнайте о роли всех элементов конфигурации</li></ul>',13)])])}const f=a(n,[["render",o]]);export{u as __pageData,f as default};
